@ApiTags('Companies')
@Controller('companies')
export class CompanyController {
	constructor(
		private readonly companyService: CompanyService,
		private readonly companyMemberService: CompanyMemberService,
	) {}

	@Get(':id')
	@ApiOperation({ summary: 'Get company by ID' })
	@ApiResponse({ status: HttpStatus.OK, description: 'Company details' })
	@ApiResponse({ status: HttpStatus.FORBIDDEN, description: 'User is not a member' })
	@ApiResponse({ status: HttpStatus.NOT_FOUND, description: 'Company not found' })
	async getById(
		@Param('id') id: string,
		@CurrentUser() user: IRequestUser,
	): Promise<ICompanyBase> {
		const membership = await this.companyMemberService.findByUserAndCompany({
			userId: user.user_id,
			companyId: id,
		});

		if (!membership) throw new ForbiddenException('User is not a member of this company');

		const company = await this.companyService.findById({ companyId: id });

		if (!company) throw new NotFoundException('Company not found');

		return company;
	}
