import '@fastify/cookie';

import {
	Body,
	Controller,
	Get,
	HttpStatus,
	Post,
	Query,
	Req,
	Res,
	UnauthorizedException,
} from '@nestjs/common';
import { ApiOperation, ApiResponse, ApiTags } from '@nestjs/swagger';
import { Throttle } from '@nestjs/throttler';
import { FastifyReply, FastifyRequest } from 'fastify';

import { AuthService } from '@modules/auth/auth.service';
import { REFRESH_TOKEN_COOKIE_NAME } from '@modules/auth/constants/auth.constant';
import { CurrentUser } from '@modules/auth/decorators/current-user.decorator';
import { Public } from '@modules/auth/decorators/public.decorator';
import { CreateCompanyDto } from '@modules/auth/dto/create-company.dto';
import { LinkAccountDto } from '@modules/auth/dto/link-account.dto';
import { TokenExchangeDto } from '@modules/auth/dto/token-exchange.dto';
import { IRequestUser } from '@modules/auth/types/auth.interface';

import { isDevEnv } from '@utils/common.util';
import { getEnv } from '@utils/get-env-variable.util';

import { FRONTEND_URL } from '@constants/env-variables.constant';

@ApiTags('Auth')
@Throttle({ default: { limit: 10, ttl: 60000 } })
@Controller('auth')
export class AuthController {
	constructor(private readonly authService: AuthService) {}

	@Public()
	@Get('github')
	@ApiOperation({ summary: 'Initiate GitHub OAuth' })
	@ApiResponse({ status: HttpStatus.FOUND, description: 'Redirect to GitHub' })
	async githubAuth(@Res() reply: FastifyReply): Promise<void> {
		const url = await this.authService.initiateOAuth({ provider: 'github' });
		reply.status(HttpStatus.FOUND).redirect(url.toString());
	}

	@Public()
	@Get('github/callback')
	@ApiOperation({ summary: 'Handle GitHub OAuth callback' })
	@ApiResponse({ status: HttpStatus.FOUND, description: 'Redirect to frontend' })
	async githubCallback(
		@Query('code') code: string,
		@Query('state') state: string,
		@Res() reply: FastifyReply,
	): Promise<void> {
		const result = await this.authService.handleCallback({
			provider: 'github',
			code,
			state,
		});
		const frontendUrl = getEnv<string>({ key: FRONTEND_URL });
		if (result.type === 'auth_code') {
			reply
				.status(HttpStatus.FOUND)
				.redirect(`${frontendUrl}/auth/callback?code=${result.code}`);
		} else {
			reply
				.status(HttpStatus.FOUND)
				.redirect(`${frontendUrl}/auth/link?linking_token=${result.linkingToken}`);
		}
	}

	@Public()
	@Get('google')
	@ApiOperation({ summary: 'Initiate Google OAuth' })
	@ApiResponse({ status: HttpStatus.FOUND, description: 'Redirect to Google' })
	async googleAuth(@Res() reply: FastifyReply): Promise<void> {
		const url = await this.authService.initiateOAuth({ provider: 'google' });
		reply.status(HttpStatus.FOUND).redirect(url.toString());
	}

	@Public()
	@Get('google/callback')
	@ApiOperation({ summary: 'Handle Google OAuth callback' })
	@ApiResponse({ status: HttpStatus.FOUND, description: 'Redirect to frontend' })
	async googleCallback(
		@Query('code') code: string,
		@Query('state') state: string,
		@Res() reply: FastifyReply,
	): Promise<void> {
		const result = await this.authService.handleCallback({
			provider: 'google',
			code,
			state,
		});
		const frontendUrl = getEnv<string>({ key: FRONTEND_URL });
		if (result.type === 'auth_code') {
			reply
				.status(HttpStatus.FOUND)
				.redirect(`${frontendUrl}/auth/callback?code=${result.code}`);
		} else {
			reply
				.status(HttpStatus.FOUND)
				.redirect(`${frontendUrl}/auth/link?linking_token=${result.linkingToken}`);
		}
	}

	@Public()
	@Post('token')
	@ApiOperation({ summary: 'Exchange auth code for JWT tokens' })
	@ApiResponse({
		status: HttpStatus.OK,
		description: 'Returns access token, sets refresh cookie',
	})
	async exchangeToken(
		@Body() dto: TokenExchangeDto,
		@Req() request: FastifyRequest,
		@Res() reply: FastifyReply,
	): Promise<void> {
		const result = await this.authService.exchangeCode({
			code: dto.code,
			ip: request.ip,
			userAgent: request.headers['user-agent'] ?? '',
			provider: 'github',
		});

		reply.setCookie(REFRESH_TOKEN_COOKIE_NAME, result.refreshToken, {
			httpOnly: true,
			secure: !isDevEnv(),
			sameSite: 'strict',
			path: '/api/auth',
			maxAge: 30 * 24 * 60 * 60,
		});

		reply.send({ access_token: result.accessToken });
	}

	@Public()
	@Throttle({ default: { limit: 5, ttl: 60000 } })
	@Post('refresh')
	@ApiOperation({ summary: 'Refresh access token using refresh token cookie' })
	@ApiResponse({
		status: HttpStatus.OK,
		description: 'Returns new access token, rotates refresh cookie',
	})
	@ApiResponse({
		status: HttpStatus.UNAUTHORIZED,
		description: 'No or invalid refresh token',
	})
	async refresh(
		@Req() request: FastifyRequest,
		@Res() reply: FastifyReply,
	): Promise<void> {
		const refreshToken = (request.cookies as Record<string, string>)[
			REFRESH_TOKEN_COOKIE_NAME
		];
		if (!refreshToken) throw new UnauthorizedException('No refresh token');

		const result = await this.authService.refreshTokens({ refreshToken });

		reply.setCookie(REFRESH_TOKEN_COOKIE_NAME, result.refreshToken, {
			httpOnly: true,
			secure: !isDevEnv(),
			sameSite: 'strict',
			path: '/api/auth',
			maxAge: 30 * 24 * 60 * 60,
		});

		reply.send({ access_token: result.accessToken });
	}

	@Post('logout')
	@ApiOperation({ summary: 'Log out current session' })
	@ApiResponse({ status: HttpStatus.OK, description: 'Successfully logged out' })
	async logout(@CurrentUser() user: IRequestUser): Promise<{ success: boolean }> {
		await this.authService.logout({
			userId: user.user_id,
			sessionId: user.session_id,
		});
		return { success: true };
	}

	@Post('logout/all')
	@ApiOperation({ summary: 'Log out all sessions for current user' })
	@ApiResponse({ status: HttpStatus.OK, description: 'All sessions terminated' })
	async logoutAll(@CurrentUser() user: IRequestUser): Promise<{ success: boolean }> {
		await this.authService.logoutAll({ userId: user.user_id });
		return { success: true };
	}

	@Post('link')
	@ApiOperation({ summary: 'Link a new OAuth provider to current account' })
	@ApiResponse({ status: HttpStatus.OK, description: 'Account linked successfully' })
	async linkAccount(
		@Body() dto: LinkAccountDto,
		@CurrentUser() user: IRequestUser,
	): Promise<{ success: boolean }> {
		await this.authService.linkAccount({
			linkingToken: dto.linking_token,
			userId: user.user_id,
		});
		return { success: true };
	}

	@Post('signup/company')
	@ApiOperation({ summary: 'Create a company for the current user' })
	@ApiResponse({
		status: HttpStatus.CREATED,
		description: 'Company created successfully',
	})
	async createCompany(
		@Body() dto: CreateCompanyDto,
		@CurrentUser() user: IRequestUser,
	): Promise<{ company_id: string }> {
		return this.authService.createCompany({
			name: dto.name,
			userId: user.user_id,
			sessionId: user.session_id,
		});
	}
}
