@ApiTags('Invitations')
@Controller()
export class InvitationController {
	constructor(
		private readonly invitationService: InvitationService,
		private readonly userService: UserService,
	) {}

	@Roles('admin')
	@Throttle({ default: { limit: 20, ttl: 3600000 } })
	@Post('companies/:id/invitations')
	@HttpCode(HttpStatus.CREATED)
	@ApiOperation({ summary: 'Create an invitation for a company' })
	@ApiResponse({ status: HttpStatus.CREATED, description: 'Invitation created' })
	@ApiResponse({
		status: HttpStatus.BAD_REQUEST,
		description: 'Pending invitation already exists',
	})
	@ApiResponse({ status: HttpStatus.FORBIDDEN, description: 'Forbidden' })
	async createInvitation(
		@Param('id') companyId: string,
		@Body() body: InvitationCreateDto,
		@CurrentUser() currentUser: IRequestUser,
	): Promise<IInvitationBase> {
		return this.invitationService.createInvitation({
			companyId,
			email: body.email,
			invitedBy: currentUser.user_id,
		});
	}

	@Roles('admin')
	@Get('companies/:id/invitations')
	@HttpCode(HttpStatus.OK)
	@ApiOperation({ summary: 'List pending invitations for a company' })
	@ApiResponse({ status: HttpStatus.OK, description: 'List of pending invitations' })
	@ApiResponse({ status: HttpStatus.FORBIDDEN, description: 'Forbidden' })
	async listPendingInvitations(
		@Param('id') companyId: string,
	): Promise<IInvitationBase[]> {
		return this.invitationService.listPendingInvitations({ companyId });
	}

	@Roles('admin')
	@Delete('companies/:id/invitations/:invId')
	@HttpCode(HttpStatus.NO_CONTENT)
	@ApiOperation({ summary: 'Revoke an invitation' })
	@ApiResponse({ status: HttpStatus.NO_CONTENT, description: 'Invitation revoked' })
	@ApiResponse({ status: HttpStatus.FORBIDDEN, description: 'Forbidden' })
	async revokeInvitation(@Param('invId') invId: string): Promise<void> {
		return this.invitationService.revokeInvitation({ invitationId: invId });
	}

	@Public()
	@Get('invitations/accept')
	@HttpCode(HttpStatus.OK)
	@ApiOperation({ summary: 'Accept an invitation via token' })
	@ApiResponse({ status: HttpStatus.OK, description: 'Invitation accepted' })
	@ApiResponse({
		status: HttpStatus.NOT_FOUND,
		description: 'Invitation not found or expired',
	})
	@ApiResponse({ status: HttpStatus.BAD_REQUEST, description: 'Email mismatch' })
	async acceptInvitation(
		@Query() query: AcceptInvitationDto,
		@CurrentUser() currentUser: IRequestUser,
	): Promise<void> {
		if (!currentUser) {
			throw new NotFoundException('Authentication required to accept invitation');
		}

		const user = await this.userService.findById({ userId: currentUser.user_id });
		if (!user) {
			throw new NotFoundException('User not found');
		}

		await this.invitationService.acceptInvitation({
			token: query.token,
			userId: currentUser.user_id,
			userEmail: user.email,
		});
	}
}

